		if (thid == 0) {
			local_offset = local_currKnode;
		}
		barrier(CLK_LOCAL_MEM_FENCE);

		if ((knodes[local_currKnode].keys[thid] <= local_key) &&
		    (knodes[local_currKnode].keys[thid + 1] > local_key)) {
			int next = knodes[local_currKnode].indices[thid];
			if ((long)next < knodes_elem) {
				local_offset = (long)next;
			}
		}

